"""Tests for databricks.vector_search.exceptions."""

import pytest

from databricks.vector_search.exceptions import (
    BadRequest,
    InvalidInputException,
    NotFound,
    PermissionDenied,
    ResourceConflict,
    ResourceDoesNotExist,
    TooManyRequests,
    VectorSearchException,
)


class TestVectorSearchException:
    def test_message_only(self):
        exc = VectorSearchException("boom")
        assert str(exc) == "boom"
        assert exc.status_code is None
        assert exc.response_content is None

    def test_carries_status_code_and_response_content(self):
        exc = VectorSearchException("nope", status_code=500, response_content=b"raw body")
        assert exc.status_code == 500
        assert exc.response_content == b"raw body"

    def test_is_subclass_of_builtin_exception(self):
        assert issubclass(VectorSearchException, Exception)


class TestExceptionHierarchy:
    @pytest.mark.parametrize(
        "cls",
        [
            InvalidInputException,
            NotFound,
            BadRequest,
            PermissionDenied,
            ResourceConflict,
            TooManyRequests,
        ],
    )
    def test_subclass_of_base(self, cls):
        assert issubclass(cls, VectorSearchException)

    @pytest.mark.parametrize(
        "cls",
        [
            InvalidInputException,
            NotFound,
            BadRequest,
            PermissionDenied,
            ResourceConflict,
            TooManyRequests,
        ],
    )
    def test_subclass_carries_fields(self, cls):
        exc = cls("msg", status_code=418, response_content=b"x")
        assert exc.status_code == 418
        assert exc.response_content == b"x"
        assert str(exc) == "msg"

    def test_base_catches_subclasses(self):
        with pytest.raises(VectorSearchException):
            raise NotFound("x", status_code=404)
        with pytest.raises(VectorSearchException):
            raise TooManyRequests("x", status_code=429)


class TestResourceDoesNotExistAlias:
    def test_alias_is_notfound(self):
        # ResourceDoesNotExist is the databricks-sdk-compat alias for NotFound;
        # they are literally the same class object.
        assert ResourceDoesNotExist is NotFound

    def test_alias_instance_is_notfound(self):
        exc = ResourceDoesNotExist("x")
        assert isinstance(exc, NotFound)
        assert isinstance(exc, VectorSearchException)
